code = """import json, pandas as pd, re

biz_cc = pd.DataFrame(var_call_IMTcmeGkHqPd7CiLhBsplHq6)

# load full business docs with descriptions (contains categories list in text)
path = var_call_5DylOhq1gvZpMXOI4WUBqMyO
with open(path, 'r') as f:
    biz_all = pd.DataFrame(json.load(f))

# parse categories from description: text after 'categories of' or 'in' listing separated by commas
# We'll extract all capitalized phrase groups separated by commas; simpler: take last clause after 'offers' keywords.

def extract_cats(desc):
    if not isinstance(desc, str):
        return []
    # common pattern: 'categories of ...' or 'services in ...' ending with '.'
    m = re.search(r"(?:categories of|services in|offers (?:a|an)? ?(?:range|diverse range|selection|options|a variety) of (?:services|offerings)?(?: in)?|specializes in|providing a range of services in)\s+(.*?)(?:\.|$)", desc, flags=re.IGNORECASE|re.DOTALL)
    s = m.group(1) if m else desc
    # remove leading quotes and filler
    s = s.replace("'", "")
    # keep after ':' if exists
    if ':' in s:
        s = s.split(':',1)[1]
    # split by commas and 'and'
    parts = re.split(r",| and ", s)
    cats=[]
    for p in parts:
        p=p.strip()
        # stop if contains address-like
        if re.search(r"\d{3,} |\b(St|Ste|Ave|Blvd|Rd|Dr|Hwy|Unit)\b", p):
            continue
        if len(p)==0:
            continue
        # trim trailing phrases
        p=re.sub(r"\b(for|to) .*","",p).strip()
        # normalize spacing
        p=re.sub(r"\s+"," ",p)
        # title-case preserve parentheses
        cats.append(p)
    # filter very long
    cats=[c for c in cats if len(c)<=60]
    return cats

biz_all['cat_list']=biz_all['description'].apply(extract_cats)

# map businessid->cats
biz_all = biz_all[['business_id','cat_list']]

# credit card businesses
cc_ids = set(biz_cc['business_id'])
cc_biz = biz_all[biz_all['business_id'].isin(cc_ids)].copy()

# explode categories
cc_expl = cc_biz.explode('cat_list').dropna(subset=['cat_list'])
cc_expl['category']=cc_expl['cat_list'].astype(str).str.strip()
cc_expl = cc_expl[cc_expl['category']!='']

# count businesses per category
counts = cc_expl.groupby('category')['business_id'].nunique().reset_index(name='business_count')
max_count = counts['business_count'].max() if len(counts) else 0
top = counts[counts['business_count']==max_count].sort_values('category').head(1)

# ratings per business
rev_avg = pd.DataFrame(var_call_SNgWFt6sXNAv4xhcf7Aj87Yp)
rev_avg['avg_rating']=rev_avg['avg_rating'].astype(float)
# map businessid->businessref
rev_avg['business_id']='businessid_'+rev_avg['business_ref'].str.replace('businessref_','',regex=False)

# compute avg rating for businesses in top category (average of business average ratings)
if len(top)==1:
    cat = top.iloc[0]['category']
    biz_in_cat = set(cc_expl.loc[cc_expl['category']==cat,'business_id'].unique())
    avg_rating = rev_avg[rev_avg['business_id'].isin(biz_in_cat)]['avg_rating'].mean()
    result = {'business_category': cat, 'business_count': int(top.iloc[0]['business_count']), 'average_rating': None if pd.isna(avg_rating) else float(avg_rating)}
else:
    result = {'business_category': None, 'business_count': 0, 'average_rating': None}

print('__RESULT__:')
print(json.dumps(result))"""

